export function distributeFlowItems({
  heights = [],
  keys = [],
  metas = [],
  availableHeight = 0,
} = {}) {
  const chunks = [{ indexes: [], keys: [] }];
  let currentHeight = 0;

  const getAvoidBreakGroupKey = (index) => {
    const meta = metas[index] ?? {};
    return meta.avoidBreakInside && meta.groupKey ? meta.groupKey : null;
  };

  const getAvoidBreakGroupHeight = (startIndex, groupKey) => {
    let height = 0;

    for (let index = startIndex; index < heights.length; index += 1) {
      if (getAvoidBreakGroupKey(index) !== groupKey) break;
      height += heights[index] ?? 0;
    }

    return height;
  };

  const startNextChunk = () => {
    if (chunks[chunks.length - 1].indexes.length > 0) {
      chunks.push({ indexes: [], keys: [] });
      currentHeight = 0;
    }
  };

  const getKeepWithNextCount = (value) => {
    if (typeof value === 'number' && Number.isFinite(value)) {
      return Math.max(0, Math.floor(value));
    }

    return value ? 1 : 0;
  };

  const getKeepWithNextHeight = (index, count) => {
    let height = 0;

    for (let offset = 1; offset <= count; offset += 1) {
      height += heights[index + offset] ?? 0;
    }

    return height;
  };

  for (let index = 0; index < heights.length; index += 1) {
    const meta = metas[index] ?? {};
    const height = heights[index] ?? 0;
    const key = keys[index] ?? String(index);
    const nextHeight = getKeepWithNextHeight(index, getKeepWithNextCount(meta.keepWithNext));
    const requiredHeight = height + nextHeight;

    if (meta.breakBefore) {
      startNextChunk();
    }

    const groupKey = getAvoidBreakGroupKey(index);
    const previousGroupKey = index > 0 ? getAvoidBreakGroupKey(index - 1) : null;
    if (
      groupKey &&
      groupKey !== previousGroupKey &&
      chunks[chunks.length - 1].indexes.length > 0 &&
      currentHeight + getAvoidBreakGroupHeight(index, groupKey) > availableHeight
    ) {
      startNextChunk();
    }

    if (
      chunks[chunks.length - 1].indexes.length > 0 &&
      currentHeight + requiredHeight > availableHeight
    ) {
      startNextChunk();
    }

    chunks[chunks.length - 1].indexes.push(index);
    chunks[chunks.length - 1].keys.push(key);
    currentHeight += height;

    if (meta.breakAfter && index < heights.length - 1) {
      startNextChunk();
    }
  }

  const populatedChunks = chunks.filter((chunk) => chunk.indexes.length > 0);
  return populatedChunks.length ? populatedChunks : [{ indexes: [], keys: [] }];
}
