import { BookDashed, Check, ChevronRight, Plus } from 'lucide-react';
import { PageFilterConfig } from './page-group-utils';
import { Button } from '../../ui/button';
import { Slider } from '../../ui/slider';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
  DropdownMenuTrigger,
} from '../../ui/dropdown-menu';

export interface PrintConfig {
  label: string;
  filter: PageFilterConfig | null;
  pageFormat?: { bleed?: number; [key: string]: any }; // PageFormat overrides to merge
}

export interface PrintConfigMap {
  [key: string]: PrintConfig;
}

/** A selectable brand kit for the dev switcher. The host owns the kit data + apply logic. */
export interface BrandKitOption {
  id: string;
  name: string;
}

export interface DevPrintControlsProps {
  modes?: PrintConfigMap;
  selectedMode?: string; // Current mode from parent
  onModeChange?: (mode: string, config: PrintConfig) => void;
  interactive: boolean;
  onInteractiveChange: (interactive: boolean) => void;
  hasReferenceRenderer?: boolean;
  referenceOpacity?: number;
  onReferenceOpacityChange?: (opacity: number) => void;
  // Brand kit switcher (dev only) — provided by the host (template/story). When `brandKits` is
  // empty/omitted the section is hidden, so the generic editor stays brand-kit agnostic.
  brandKits?: BrandKitOption[];
  activeBrandKitId?: string;
  onSelectBrandKit?: (id: string) => void;
  // Load an arbitrary published kit for testing (a brandkit.json URL, a kit id, or raw JSON). The
  // host fetches/parses + applies it; when omitted the "Add published kit…" action is hidden.
  onAddBrandKit?: (input: string) => void;
}

// Sentinel mode values for the unified Print Preview list.
const EDIT_VALUE = '__edit__';
const PRINT_VALUE = '__print__';

/** One checkable row. `keepOpen` keeps the menu open on select (handy for rapid brand-kit compares). */
function OptionRow({
  checked,
  label,
  onSelect,
  keepOpen = false,
}: {
  checked: boolean;
  label: string;
  onSelect: () => void;
  keepOpen?: boolean;
}) {
  return (
    <DropdownMenuItem
      onSelect={(event) => {
        if (keepOpen) event.preventDefault();
        onSelect();
      }}
      className="flex items-center gap-2"
    >
      {checked ? <Check className="w-3 h-3 text-gray-400" /> : <span className="w-3 h-3" />}
      <span className="flex-1 truncate">{label}</span>
    </DropdownMenuItem>
  );
}

/** A submenu trigger showing the section name + the current value, with a chevron affordance. */
function SubTriggerRow({ label, value }: { label: string; value?: string }) {
  return (
    <DropdownMenuSubTrigger className="flex items-center justify-between gap-4 text-xs">
      <span className="text-gray-700">{label}</span>
      <span className="flex items-center gap-1 text-gray-400">
        {value ? <span className="max-w-[110px] truncate">{value}</span> : null}
        <ChevronRight className="w-3.5 h-3.5" />
      </span>
    </DropdownMenuSubTrigger>
  );
}

/**
 * Developer controls — Print Preview and Brand Kit open as submenus; the Reference Overlay slider is
 * pinned to the bottom. Rendered only when devtools are enabled.
 */
export function DevPrintControls({
  modes,
  selectedMode: selectedModeProp,
  onModeChange,
  interactive,
  onInteractiveChange,
  hasReferenceRenderer = false,
  referenceOpacity = 50,
  onReferenceOpacityChange,
  brandKits,
  activeBrandKitId,
  onSelectBrandKit,
  onAddBrandKit,
}: DevPrintControlsProps) {
  const modeKeys = modes ? Object.keys(modes) : [];

  // One coherent Print Preview list: "Edit" on top, then the template's print modes (or a single
  // "Print" when none are defined).
  const printOptions: Array<{ value: string; label: string }> = [
    { value: EDIT_VALUE, label: 'Edit' },
    ...(modeKeys.length > 0
      ? modeKeys.map((key) => ({ value: key, label: modes![key].label }))
      : [{ value: PRINT_VALUE, label: 'Print' }]),
  ];
  const selectedPrint = interactive ? EDIT_VALUE : selectedModeProp || modeKeys[0] || PRINT_VALUE;
  const selectedPrintLabel = printOptions.find((o) => o.value === selectedPrint)?.label ?? 'Edit';

  const handlePrintSelect = (value: string) => {
    if (value === EDIT_VALUE) {
      onInteractiveChange(true);
      return;
    }
    onInteractiveChange(false);
    if (value !== PRINT_VALUE && modes && modes[value]) {
      onModeChange?.(value, modes[value]);
    }
  };

  const hasBrandKits = !!brandKits && brandKits.length > 0;
  const activeKitName = brandKits?.find((k) => k.id === activeBrandKitId)?.name;

  const handleAddPublished = () => {
    const input = window.prompt(
      'Add a published brand kit to test — paste a brandkit.json URL, a kit id, or raw JSON:',
    );
    if (input && input.trim()) onAddBrandKit?.(input.trim());
  };

  return (
    <DropdownMenu modal={false}>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="sm"
          className={`text-xs font-medium text-gray-700 hover:bg-gray-100/80 h-7 px-2.5 ${!interactive ? 'bg-gray-100/80' : ''}`}
        >
          <BookDashed className="w-3.5 h-3.5" />
          <span className="text-[10px] uppercase tracking-wide">Dev</span>
        </Button>
      </DropdownMenuTrigger>

      <DropdownMenuContent align="end" className="min-w-[200px]">
        {/* Print Preview — submenu */}
        <DropdownMenuSub>
          <SubTriggerRow label="Print Preview" value={selectedPrintLabel} />
          <DropdownMenuSubContent className="min-w-[180px]">
            {printOptions.map((opt) => (
              <OptionRow
                key={opt.value}
                checked={selectedPrint === opt.value}
                label={opt.label}
                onSelect={() => handlePrintSelect(opt.value)}
              />
            ))}
          </DropdownMenuSubContent>
        </DropdownMenuSub>

        {/* Brand Kit — submenu */}
        {hasBrandKits && (
          <DropdownMenuSub>
            <SubTriggerRow label="Brand Kit" value={activeKitName} />
            <DropdownMenuSubContent className="min-w-[200px]">
              {brandKits!.map((kit) => (
                <OptionRow
                  key={kit.id}
                  checked={activeBrandKitId === kit.id}
                  label={kit.name}
                  keepOpen
                  onSelect={() => onSelectBrandKit?.(kit.id)}
                />
              ))}
              {onAddBrandKit && (
                <>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem
                    onSelect={(event) => {
                      event.preventDefault();
                      handleAddPublished();
                    }}
                    className="flex items-center gap-2"
                  >
                    <Plus className="w-3 h-3 text-gray-400" />
                    <span className="flex-1">Add published kit…</span>
                  </DropdownMenuItem>
                </>
              )}
            </DropdownMenuSubContent>
          </DropdownMenuSub>
        )}

        {/* Reference Overlay — always pinned to the bottom */}
        {hasReferenceRenderer && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuLabel className="text-xs text-gray-500">Reference Overlay</DropdownMenuLabel>
            <div className="px-2 py-2">
              <div className="flex items-center justify-between text-xs text-gray-600">
                <span>Opacity</span>
                <span>{referenceOpacity}%</span>
              </div>
              <div className="pt-2">
                <Slider
                  value={[referenceOpacity]}
                  min={0}
                  max={100}
                  step={5}
                  onValueChange={(value) => {
                    const next = value[0] ?? referenceOpacity;
                    onReferenceOpacityChange?.(next);
                  }}
                />
              </div>
              <div className="pt-2 flex items-center justify-between text-xs text-gray-500">
                <span>Hidden</span>
                <span>Solid</span>
              </div>
            </div>
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
