/**
 * Standard page size calculations in millimeters
 */
export class PageSizeUtils {
    static PAGE_SIZES = {
        // A series
        'A0': { width: 841, height: 1189 },
        'A1': { width: 594, height: 841 },
        'A2': { width: 420, height: 594 },
        'A3': { width: 297, height: 420 },
        'A4': { width: 210, height: 297 },
        'A5': { width: 148, height: 210 },
        'A6': { width: 105, height: 148 },
        
        // B series
        'B0': { width: 1000, height: 1414 },
        'B1': { width: 707, height: 1000 },
        'B2': { width: 500, height: 707 },
        'B3': { width: 353, height: 500 },
        'B4': { width: 250, height: 353 },
        'B5': { width: 176, height: 250 },
        'B6': { width: 125, height: 176 },
        
        // C series (envelopes)
        'C0': { width: 917, height: 1297 },
        'C1': { width: 648, height: 917 },
        'C2': { width: 458, height: 648 },
        'C3': { width: 324, height: 458 },
        'C4': { width: 229, height: 324 },
        'C5': { width: 162, height: 229 },
        'C6': { width: 114, height: 162 },
        
        // US Sizes
        'LETTER': { width: 216, height: 279 },
        'LEGAL': { width: 216, height: 356 },
        'TABLOID': { width: 279, height: 432 },
        'LEDGER': { width: 432, height: 279 }
    };
    /**
     * Get all available page size format names
     * @returns {string[]} Array of page size format names
     */
    static getStandardFormats() {
        return ['Custom', 'A3', 'A4', 'A5', 'LETTER', 'LEGAL'];
    }

    /**
     * Get dimensions for a specific page size
     * @param {Object} options - Configuration options
     * @param {string} options.format - Page size format (e.g., 'A4', 'LETTER')
     * @param {string} [options.orientation='portrait'] - Page orientation ('portrait' or 'landscape')
     * @returns {{ width: number, height: number } | null} Dimensions in millimeters
     */
    static getDimensions({ 
        format, 
        orientation = 'portrait'
    }) {
        const size = this.PAGE_SIZES[format.toUpperCase()];
        if (!size) return null;

        return orientation === 'landscape' ? 
            { 
                width: size.height, 
                height: size.width
            } : 
            { 
                width: size.width, 
                height: size.height
            };
    }

    /**
     * Convert millimeters to pixels at a given DPI
     * @param {number} mm - Value in millimeters
     * @param {number} dpi - Dots per inch (default: 72)
     * @returns {number} Value in pixels
     */
    static mmToPx(mm, dpi = 72) {
        return (mm * dpi) / 25.4;
    }

    /**
     * Get dimensions in pixels for a specific page size
     * @param {Object} options - Configuration options
     * @param {string} options.format - Page size format (e.g., 'A4', 'LETTER')
     * @param {string} [options.orientation='portrait'] - Page orientation ('portrait' or 'landscape')
     * @param {number} [options.dpi=72] - Dots per inch
     * @returns {{ width: number, height: number } | null} Dimensions in pixels
     */
    static getDimensionsInPx({ 
        format, 
        orientation = 'portrait', 
        dpi = 72
    }) {
        const dimensions = this.getDimensions({ 
            format, 
            orientation
        });
        if (!dimensions) return null;

        return {
            width: this.mmToPx(dimensions.width, dpi),
            height: this.mmToPx(dimensions.height, dpi)
        };
    }

    /**
     * Check if a format exists
     * @param {string} format - Page size format to check
     * @returns {boolean} Whether the format exists
     */
    static hasFormat(format) {
        return format.toUpperCase() in this.PAGE_SIZES;
    }

    /**
     * Get all available formats
     * @returns {string[]} Array of available format names
     */
    static getAvailableFormats() {
        return Object.keys(this.PAGE_SIZES);
    }

    static toValidCustomDimension(value) {
        const numericValue = typeof value === 'string' && value.trim() !== ''
            ? Number(value)
            : value;

        return typeof numericValue === 'number' &&
            Number.isFinite(numericValue) &&
            numericValue > 10 &&
            numericValue < 4000
            ? numericValue
            : null;
    }

    static resolveDimensions(args = {}) {
        const { format, orientation, width, height } = args;
        const normalizedFormat = typeof format === 'string' ? format : '';
        const isCustom = !normalizedFormat || normalizedFormat.toLowerCase() === 'custom';
        const customWidth = this.toValidCustomDimension(width);
        const customHeight = this.toValidCustomDimension(height);

        if (isCustom && customWidth !== null && customHeight !== null) {
            return { width: customWidth, height: customHeight };
        }

        const fallbackFormat = isCustom ? 'A4' : normalizedFormat;
        return this.getDimensions({ format: fallbackFormat || 'A4', orientation }) ??
            this.getDimensions({ format: 'A4', orientation }) ??
            { width: 210, height: 297 };
    }

    static pageParams(paginationType, args = {}) {
        if (typeof document === 'undefined') return;
        
        const {format, orientation, bleed, showBleed, compatibility, printCssRaw, printCssUrl, preview} = args;
        const dimensions = this.resolveDimensions(args);

        if (dimensions) {
            document.documentElement.style.setProperty('--uhuu-page-width', `${dimensions.width}mm`);
            document.documentElement.style.setProperty('--uhuu-page-height', `${dimensions.height}mm`);        
        }

        document.documentElement.style.setProperty('--uhuu-page-bleed', `${Math.min(Math.max(bleed ?? 0, 0), 400)}mm`);

        const page = { 
            paginationType,
            format, 
            orientation, 
            bleed, 
            width: dimensions?.width, 
            height: dimensions?.height, 
            preview, 
            showBleed,
            compatibility,
            printCssRaw,
            printCssUrl 
        };

        return { page };  
    }
}

export default PageSizeUtils;
